import React, { Component, Fragment } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { appActions, breadCrumbActions, errorNotice, headerActions, headerStrings, HighlightedInfo, hirUtil, history, monthSelections, MyDialog, MyTable, SimplePagination, simplePaginationConfig, StageHeaderPlane } from '../utils';
import { hirRouteNames } from '../routeNames';
import { HIRButton, HIRStartEndDates } from '../Includes';
import { Add, CalendarToday, CalendarViewDay, Delete, Edit, Undo } from '@material-ui/icons';
import { HIRFindPatient } from '../HIRPatients';
import { hirAccountActions } from '../HIRAccounts';
import { Button, Checkbox, FormControlLabel, IconButton, TableCell, Typography } from '@material-ui/core';
import Calendar from 'react-calendar';
import exportFromJSON from 'export-from-json'


const style = theme => ({
    root: {
    },
    cell : {
        padding : 5,
        fontSize : 11,
    },
    iconBtn : {
        padding : 3 
    },
    headerContainer : {
        display : 'flex',
        marginBottom : 20,
        alignItems : "center",
    },
    total : {
        display : "flex", 
        justifyContent : "center", 
        alignItems : "center",
        color : "white",
        backgroundColor : theme.colors.primary1,
        borderRadius : 20,
        fontSize : 14,
        fontWeight : "bold",
        padding : 10
    },
    dialogDateContainer : {
        display : "flex",
        flexDirection : "column",
        alignItems : "center",
        justifyContent : "center"
    },
    download : {
        fontSize : 12,
        textDecoration : "underline",
        "&:hover" : {
            cursor : "pointer",
        }
    }
})
class _HIRAccountRefunds extends Component {
    constructor(props) {
        super(props);
        this.state = {
            dialogType : "date",
            openDialog : false,
            filter : {
                monthOnly : false,
                startDate : null,
                endDate : null,
                date : new Date()
            }
        }
        const {dispatch} = props;
        headerActions({
            [headerStrings.headerTitle] : "Refunds",
            [headerStrings.backButtonAction] : null
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", pathname : hirRouteNames.dashboard},
            {name : "Refunds", pathname : hirRouteNames.patients}
        ])(dispatch);
    }
    componentDidMount() {
        this.refundConfig();
    }
    
    searchAction(keyword){
        this.pageControl.search(keyword);
    }
    searchPatientRowAction = row => () => {
        this.setState({
            dialogType : "refund",
            patient : row
        })
    }
    closeDialog = () => this.setState({openDialog : false, dialogType : "", patient : null, refund : null});
    onUpdateRefund(data, callback) {
        const {dispatch} = this.props,
        {refund} = this.state,
        {_id : refundId} = refund || {};
        if(!refundId) return errorNotice("There is no patient selected", dispatch);
        hirAccountActions.updateRefund(refundId, data, done => {
            callback && callback(done);
            if(done){
                this.refundConfig();
                this.closeDialog();
            }
        })(dispatch);
    }
    createRefund(data, callback) {
        const {dispatch} = this.props,
        {patient} = this.state,
        patientId = patient && patient._id;
        if(!patientId) return errorNotice("There is no patient selected", dispatch);
        hirAccountActions.createRefund({...data, patientId}, done => {
            callback && callback(done);
            if(done){
                this.refundConfig();
                this.closeDialog();
            }
        })(dispatch);
    }
    deleteRefund(refund){
        const {dispatch} = this.props;
        appActions.showSnackDialog(
            "Sure! You want to delete this refund? This will affect accounts",
            [<Button key="deleteRefund" onClick={()=>{
                appActions.closeSnackDialog()(dispatch);
                hirAccountActions.deleteRefund(refund && refund._id, done => {
                    if(done){
                        this.closeDialog();
                        this.refundConfig();
                    }
                })(dispatch);
            }}>Continue</Button>]
        )(dispatch);
    }
    refundConfig(callback){
        this.pageControl = simplePaginationConfig(
            this, this.getRefunds, this.props.dispatch,
            "refunds", 50, null, null, this.getRefundMinMaxIds,
            this.searchRefunds, this.getSearchRefundMinMaxIds
        )
        this.setState({keyword : ""});
        this.pageControl.getAction(callback);
    }
    getFilter(){
        const {filter} = this.state;
        return {...filter, detail : true};
    }
    getRefunds = (rows, skip, sort, max, callback)=>dispatch => {
        const filter = this.getFilter();
        hirAccountActions.getRefunds(filter, rows, skip, sort, max, callback)(dispatch);
    }
    getRefundMinMaxIds = (sort, callback)=>dispatch => {
        const filter = this.getFilter();
        hirAccountActions.getRefundMinMaxIds(filter, sort, callback)(dispatch);
    }
    searchRefunds = (keyword, rows, skip, sort, max, callback)=>dispatch => {
        const filter = this.getFilter();
        hirAccountActions.searchRefunds(filter, keyword, rows, skip, sort, max, callback)(dispatch);
    }
    getSearchRefundMinMaxIds = (keyword, sort, callback)=>dispatch => {
        const filter = this.getFilter();
        hirAccountActions.getSearchRefundMinMaxIds(filter, keyword, sort, callback)(dispatch);
    }
    veiwPatient = patientId => e => {
        e.stopPropagation();
        history.push(hirRouteNames.patientView_+patientId);
    }
    revertRefund = refundId => e => {
        const {dispatch} = this.props;
        e.stopPropagation();
        appActions.showSnackDialog(
            "Sure! You want to revert this refund?",
            [<Button key="revertFund" onClick={()=>{
                appActions.closeSnackDialog()(dispatch);
                hirAccountActions.revertRefund(refundId, done => {
                    done && this.refundConfig();
                })(dispatch);
            }}>Continue</Button>]
        )(dispatch);
        hirAccountActions.revertRefund()
    }
    cellMapFormat({row, cellMap}){
        const {classes} = this.props;
        switch(cellMap){
            case "action" : return <TableCell className={classes.cell}>
                {hirUtil.isAdmin() && <div>
                    <IconButton className={classes.iconBtn}
                        onClick={this.revertRefund(row._id)}
                        title="Revert refund"
                    >
                        <Undo fontSize="small" color="secondary"/>
                    </IconButton>
                </div>}
            </TableCell>
            case "actionDate" : return <TableCell className={classes.cell}>
                {new Date(row[cellMap]).toLocaleDateString()}
            </TableCell>
            case "credit" : return <TableCell className={classes.cell}>
                {new Number(row[cellMap]).toLocaleString()}
            </TableCell>
            case "_id" : return <TableCell className={classes.cell}>
                {hirUtil._id(row[cellMap])}
            </TableCell>
            case "name" : 
                const {_id : patientId, myProfile} = row.patient || {},
                {lastName, firstName} = myProfile || {},
                name = (lastName ? lastName : "") + " " + (firstName ? firstName : "");
                return <TableCell className={classes.cell}>
                    <u className={classes.cellName}
                        onClick={this.veiwPatient(patientId)}>
                        {name}
                    </u>
                </TableCell>
            default : return <TableCell className={classes.cell}>
                {row[cellMap]}
            </TableCell>
        }
    }
    changeFilter = name => (e) => {
        const value = e.target.checked;
        this.setState({filter : {...this.state.filter, [name] : value}}, ()=>{
            this.refundConfig();
        });
    }
    header = ["ID", "Patient", "Refund", "Description", "Date"];
    headerMapper = ["_id", "name", "credit", "description", "actionDate"];
    dateSearchBtn(){
        const {dateSearchLoading} = this.state;
        return <div style={{marginTop : 20}}>
            <HIRButton type="primary" 
                loading={dateSearchLoading}
                onClick={()=>{
                    this.closeDialog();
                    this.refundConfig()
                }}>
                    Get Refunds
                </HIRButton>
        </div>
    }
    downloadCVS(data){
        const {dispatch} = this.props,
        fileName = 'refunds',
        exportType = 'csv',
        mainData = []
        if(data) for (let i = 0; i < data.length; i++) {
            const dataObject = data[i],
            mainD = {},
            {myProfile} = dataObject?.patient || {};
            for (let j = 0; j < this.headerMapper.length; j++) {
                const mapper = this.headerMapper[j];
                let value = dataObject[mapper],
                header = this.header[j];
                switch(mapper){
                    case "actionDate" : 
                        mainD[header] = value && new Date(value).toLocaleDateString(); 
                        break;
                    case "credit" : 
                        mainD[header] = value && new Number(value).toLocaleString(); 
                        break;
                    case "_id" : 
                        mainD[header] = dataObject?.patient?._id;
                        break;
                    case "actionDate" : 
                        mainD[header] = new Date(value).toLocaleDateString();
                        break;
                    case "name" : 
                        const {lastName, firstName} = myProfile || {},
                        name = (lastName ? lastName : "") + " " + (firstName ? firstName : "");
                        mainD[header] = name;
                        break;
                    default: mainD[header] = dataObject[mapper]; break;
                }
            }
            mainData.push(mainD);
        }
        appActions.showSnackDialog(
            "You are about to download a CSV file. Do you want to continue?",
            [<Button key="downloadCSV" onClick={()=>{
                appActions.closeSnackDialog()(dispatch);
                exportFromJSON({ data : mainData, fileName, exportType })
            }}>Continue</Button>]
        )(dispatch);
    }
    render() {
        const {classes} = this.props,
        {openDialog, dialogType, patient, refunds, refund, filter} = this.state,
        {myProfile} = patient || {},
        {monthOnly, date, startDate, endDate} = filter || {},
        {lastName, firstName} = myProfile || {},
        name = (lastName ? lastName : "") + " " + (firstName ? firstName : "");
        let total = 0;
        if(refunds) for (let i = 0; i < refunds.length; i++) {
            const {credit} = refunds[i];
            total += credit;
        }
        let header, headerMapper;
        if(hirUtil.isAdmin){
            header = [...this.header, "Actions"];
            headerMapper = [...this.headerMapper, "action"];
        }
        return (
            <div className={classes.root}>
                <div style={{marginBottom : 20}}>
                    <StageHeaderPlane
                        isRequired={false}
                        visible={true}
                        refreshCallback={()=>this.setState({filter : {date : new Date(), startDate : null, endDate : null}}, this.refundConfig.bind(this))}
                        searchActions={this.searchAction.bind(this)}
                        />
                </div>
                <div className={classes.headerContainer}>
                    <IconButton onClick={()=>this.setState({openDialog : true, dialogType : "date"})}>
                        <CalendarToday color="secondary"/>
                    </IconButton>
                    <FormControlLabel
                            value={monthOnly}
                            onChange={this.changeFilter("monthOnly")}
                        control={<Checkbox/>}
                        label={<Typography style={{fontSize : 14}}>Month only view</Typography>}
                        />
                    {hirUtil.isAdmin() && <div><HIRButton
                        type="secondary"
                        onClick={()=>this.setState({openDialog : true, dialogType : "dateRange"})}
                        classes={{btn : classes.marginRight}}
                        >
                            <CalendarViewDay fontSize="small"/>
                            Date Range
                    </HIRButton></div>}
                    <div style={{display : "flex", flexGrow : 1}}/>
                    <div className={classes.total}>
                        Total : N{Number(total).toLocaleString()}
                    </div>
                </div>
                
                <div style={{marginTop : 20}}>
                    <MyTable
                    title={<small>{dialogType === "date" ? 
                    (monthOnly ? 
                        date.getFullYear()+", "+(monthSelections.find(item=>item.value ==date.getMonth()+1).name) : 
                        date.toDateString()
                    )  : new Date(startDate).toLocaleDateString() + " to " + 
                    new Date(endDate).toLocaleDateString()}
                    </small>}
                        header={header}
                        dataMap={headerMapper}
                        CellMap={this.cellMapFormat.bind(this)}
                        data={refunds}
                        />
                    {this.pageControl && <div style={{marginTop : 20}}>
                        <SimplePagination
                            nextBtnClick={this.pageControl.nextBtnOnClick()}
                            nextBtnProps={{
                                disabled : this.pageControl.nextBtnDisabled()
                            }}
                            prevBtnClick={this.pageControl.prevBtnOnClick()}
                            prevBtnProps={{
                                disabled : this.pageControl.prevBtnDisabled()
                            }}
                            />
                    </div>}
                    <div style={{display : "flex", justifyContent : "flex-end", paddingBottom : 20}}>
                        <a onClick={()=>this.downloadCVS(refunds)} className={classes.download}>
                            Download CSV file
                        </a>
                    </div>
                </div>
                <MyDialog 
                    within
                    open={openDialog}
                    close={this.closeDialog.bind(this)}
                >
                    <div className={classes.dialogDateContainer}>
                        {dialogType === "date" && <Fragment>
                                <Typography paragraph className={classes.header}>Search Refund by dates</Typography>
                            <Calendar
                                value={date}
                                onChange={date=>this.setState(state=>({filter : {
                                    ...state.filter, date, startDate : null, endDate : null
                                }}))}/>
                            {this.dateSearchBtn()}
                        </Fragment>}
                        {dialogType === "dateRange" && <Fragment>
                            <Typography paragraph className={classes.header}>Search Refund by dates range</Typography>
                            <HIRStartEndDates
                                noTitle
                                containerProps={{
                                    style : {
                                        width : "100%"
                                    }
                                }}
                                onDateChange={(startDate, endDate)=>this.setState(state=>({
                                    filter : {...state.filter, startDate, endDate, date : null}
                                }))}/>
                            {this.dateSearchBtn()}
                        </Fragment>}
                    </div>
                </MyDialog>
            </div>
        );
    }
}


_HIRAccountRefunds.propTypes = {
    classes : PropTypes.object.isRequired,
};
const mapStateToProps = state => ({
    state
})


export const HIRAccountRefunds = connect(mapStateToProps)(withStyles(style)(_HIRAccountRefunds));
export {HIRAccountRefunds as default}